import 'package:flame/components.dart';

import 'country_data.dart';

/// Available game regions.
enum GameRegion {
  world,
  usStates,
  ukCounties,
  caribbean,
  ireland,
  canadianProvinces,
  europe,
  africa,
  asia,
  latinAmerica,
  oceania,
}

/// Whether a region uses a flat map projection instead of the globe.
///
/// Flat-map regions show a static satellite view with the plane moving
/// across the screen, rather than the globe-centred view.
bool isRegionalFlatMap(GameRegion region) {
  switch (region) {
    case GameRegion.world:
    case GameRegion.caribbean:
    case GameRegion.europe:
    case GameRegion.africa:
    case GameRegion.asia:
    case GameRegion.latinAmerica:
    case GameRegion.oceania:
      return false;
    case GameRegion.usStates:
    case GameRegion.ukCounties:
    case GameRegion.ireland:
    case GameRegion.canadianProvinces:
      return true;
  }
}

extension GameRegionExtension on GameRegion {
  String get displayName {
    switch (this) {
      case GameRegion.world:
        return 'World';
      case GameRegion.usStates:
        return 'US States';
      case GameRegion.ukCounties:
        return 'UK Counties';
      case GameRegion.caribbean:
        return 'Caribbean';
      case GameRegion.ireland:
        return 'Ireland';
      case GameRegion.canadianProvinces:
        return 'Canada';
      case GameRegion.europe:
        return 'Europe';
      case GameRegion.africa:
        return 'Africa';
      case GameRegion.asia:
        return 'Asia';
      case GameRegion.latinAmerica:
        return 'Latin America';
      case GameRegion.oceania:
        return 'Oceania';
    }
  }

  String get description {
    switch (this) {
      case GameRegion.world:
        return 'Navigate the entire globe';
      case GameRegion.usStates:
        return 'Explore all 50 US states';
      case GameRegion.ukCounties:
        return 'Discover counties of the UK';
      case GameRegion.caribbean:
        return 'Island hop through the Caribbean';
      case GameRegion.ireland:
        return 'Tour all 32 counties of Ireland';
      case GameRegion.canadianProvinces:
        return 'Fly across Canada\'s provinces';
      case GameRegion.europe:
        return 'Test your knowledge of European countries';
      case GameRegion.africa:
        return 'Navigate the African continent';
      case GameRegion.asia:
        return 'Explore the diverse nations of Asia';
      case GameRegion.latinAmerica:
        return 'Fly through Central & South America';
      case GameRegion.oceania:
        return 'Discover the Pacific island nations';
    }
  }

  /// Map bounds for the region [minLng, minLat, maxLng, maxLat]
  List<double> get bounds {
    switch (this) {
      case GameRegion.world:
        return [-180, -85, 180, 85];
      case GameRegion.usStates:
        return [-125, 24, -66, 50];
      case GameRegion.ukCounties:
        return [-11, 49, 3, 61];
      case GameRegion.caribbean:
        return [-85, 10, -59, 28];
      case GameRegion.ireland:
        return [-11, 51, -5, 56];
      case GameRegion.canadianProvinces:
        return [-141, 42, -52, 72];
      case GameRegion.europe:
        return [-25, 34, 45, 72];
      case GameRegion.africa:
        return [-18, -35, 52, 38];
      case GameRegion.asia:
        return [25, -12, 150, 55];
      case GameRegion.latinAmerica:
        return [-118, -56, -34, 33];
      case GameRegion.oceania:
        return [110, -50, 180, 0];
    }
  }

  /// Center point for the region
  Vector2 get center {
    final b = bounds;
    return Vector2((b[0] + b[2]) / 2, (b[1] + b[3]) / 2);
  }

  /// Required level to unlock this region
  int get requiredLevel {
    switch (this) {
      case GameRegion.world:
        return 1;
      case GameRegion.usStates:
        return 3;
      case GameRegion.canadianProvinces:
        return 4;
      case GameRegion.ukCounties:
        return 5;
      case GameRegion.europe:
        return 3;
      case GameRegion.africa:
        return 5;
      case GameRegion.asia:
        return 7;
      case GameRegion.latinAmerica:
        return 9;
      case GameRegion.oceania:
        return 11;
      case GameRegion.caribbean:
        return 7;
      case GameRegion.ireland:
        return 10;
    }
  }

  /// Whether this region uses a flat map projection instead of the globe.
  bool get isFlatMap => isRegionalFlatMap(this);
}

/// Regional area shape (state, county, island, etc.)
class RegionalArea {
  const RegionalArea({
    required this.code,
    required this.name,
    required this.points,
    this.polygons,
    this.capital,
    this.population,
    this.funFact,
  });

  final String code;
  final String name;

  /// Flat list of all points (used for hit-testing, centroids, etc.)
  final List<Vector2> points;

  /// Separate polygon rings. When non-null, renderers should draw each ring
  /// as its own sub-path to avoid artefacts between disjoint polygons.
  final List<List<Vector2>>? polygons;
  final String? capital;
  final int? population;
  final String? funFact;
}

/// Regional data provider.
abstract class RegionalData {
  /// Get areas for a region
  static List<RegionalArea> getAreas(GameRegion region) {
    switch (region) {
      case GameRegion.world:
        return CountryData.countries
            .map(
              (c) => RegionalArea(
                code: c.code,
                name: c.name,
                points: c.allPoints,
                polygons: c.polygons,
                capital: c.capital,
              ),
            )
            .toList();
      case GameRegion.usStates:
        return _usStates;
      case GameRegion.ukCounties:
        return _ukCounties;
      case GameRegion.caribbean:
        return _caribbeanIslands;
      case GameRegion.ireland:
        return _irelandCounties;
      case GameRegion.canadianProvinces:
        return _canadianProvinces;
      case GameRegion.europe:
        return _countriesForCodes(_europeCodes);
      case GameRegion.africa:
        return _countriesForCodes(_africaCodes);
      case GameRegion.asia:
        return _countriesForCodes(_asiaCodes);
      case GameRegion.latinAmerica:
        return _countriesForCodes(_latinAmericaCodes);
      case GameRegion.oceania:
        return _countriesForCodes(_oceaniaCodes);
    }
  }

  static List<RegionalArea> _countriesForCodes(Set<String> codes) {
    return CountryData.countries
        .where((c) => codes.contains(c.code))
        .map(
          (c) => RegionalArea(
            code: c.code,
            name: c.name,
            points: c.allPoints,
            polygons: c.polygons,
            capital: c.capital,
          ),
        )
        .toList();
  }

